   122→
   123→        if (windowAssigner instanceof MergingWindowAssigner) {
   124→            MergingWindowSet<W> mergingWindows = getMergingWindowSet();
   125→
   126→            for (W window : elementWindows) {
   127→
   128→                // adding the new window might result in a merge, in that case the actualWindow
   129→                // is the merged window and we work with that. If we don't merge then
   130→                // actualWindow == window
   131→                W actualWindow =
   132→                        mergingWindows.addWindow(
   133→                                window,
