        Iterable<StreamRecord<IN>> contents = evictingWindowState.get();
        if (contents != null) {
            emitWindowContents(triggerContext.window, contents, evictingWindowState);
        }
    }

    if (triggerResult.isPurge()) {
        evictingWindowState.clear();

