        for (Object elem : testHarness.getOutput()) {
            if (elem instanceof StreamRecord) {
                StreamRecord<Tuple2<String, Integer>> el =
                        (StreamRecord<Tuple2<String, Integer>>) elem;
                assertThat(expectedOutput).contains(el);
            }
        }
        testHarness.close();
    }

