            // add elements out-of-order
            testHarness.processElement(new StreamRecord<>(new Tuple2<>("key2", 1), 0));
            testHarness.processElement(new StreamRecord<>(new Tuple2<>("key2", 33), 1000));

            // do a snapshot, close and restore again
